#include<bits/stdc++.h>
using namespace std;
char a[1000010],b[1000010];
int nxt[1000010];
int main()
{
    scanf("%s%s",a+1,b+1);
    int n=strlen(a+1),m=strlen(b+1);
    int j=0;
    for(int i=2;i<=m;i++)
    {
        while(j&&b[j+1]!=b[i])
        {
            j=nxt[j];
        }
        if(b[j+1]==b[i])
        {
            j++;
            nxt[i]=j;
        }
    }
    j=0;
    for(int i=1;i<=n;i++)
    {
        while(j&&b[j+1]!=a[i])
        {
            j=nxt[j];
        }
        if(b[j+1]==a[i])
        {
            j++;
        }
        if(j==m)
        {
            printf("%d\n",i-m+1);
            j=nxt[j];
        }
    }
    for(int i=1;i<=m;i++)
    {
        printf("%d ",nxt[i]);
    }
    return 0;
}
